# Thách thức 3 — Anchoring: giá trị phụ thuộc ngày tham chiếu (DCT)
from datetime import date, timedelta

def anchor_next_july(dct: date) -> date:
    """Tính 'Next July' từ DCT — kết quả khác nhau theo tháng hiện tại."""
    target_month = 7
    if dct.month < target_month:
        return date(dct.year, target_month, 1)
    else:
        return date(dct.year + 1, target_month, 1)

dcts = [date(1990, 3, 1), date(1990, 8, 1), date(1990, 7, 15)]
for d in dcts:
    result = anchor_next_july(d)
    print(f"  DCT={d}  'Next July' -> {result}")

